import java.io.*;
import javax.servlet.*;
import javax.servlet.http.*;
import org.apache.commons.text.StringEscapeUtils;

public class SecureServlet extends HttpServlet {
    protected void doGet(HttpServletRequest request, HttpServletResponse response)
            throws ServletException, IOException {
        String userInput = request.getParameter("input");

        // Validate user input to prevent XSS attacks
        if (userInput != null && !userInput.isEmpty()) {
            // Encode user input to prevent XSS attacks
            String safeUserInput = StringEscapeUtils.escapeHtml4(userInput);

            // Use safeUserInput in the response
            String output = "<h1>Welcome " + safeUserInput + "</h1>";

            response.setContentType("text/html");
            PrintWriter out = response.getWriter();
            out.println(output);
        } else {
            // Handle empty or null input gracefully
            response.setContentType("text/plain");
            PrintWriter out = response.getWriter();
            out.println("Invalid input");
        }
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
